from itertools import permutations

class Solution:
    def maxCompatibilitySum(self, students, mentors):
        m = len(students)
        score = [[sum(1 for a, b in zip(students[i], mentors[j]) if a == b) for j in range(m)] for i in range(m)]
        best = 0
        for perm in permutations(range(m)):
            best = max(best, sum(score[i][perm[i]] for i in range(m)))
        return best

