class Solution:
    def maxCompatibilitySum(self, students, mentors):
        m = len(students)
        score = [[sum(1 for a, b in zip(students[i], mentors[j]) if a == b) for j in range(m)] for i in range(m)]
        full = 1 << m
        dp = [-1] * full
        dp[0] = 0
        for mask in range(full):
            if dp[mask] < 0:
                continue
            i = bin(mask).count('1')
            if i >= m:
                continue
            for j in range(m):
                if not (mask >> j) & 1:
                    nm = mask | (1 << j)
                    val = dp[mask] + score[i][j]
                    if val > dp[nm]:
                        dp[nm] = val
        return dp[full - 1]

