var maxCompatibilitySum = function(students, mentors) {
    const m = students.length;
    const score = [];
    for (let i = 0; i < m; i++) {
        score.push([]);
        for (let j = 0; j < m; j++) {
            let s = 0;
            for (let k = 0; k < students[i].length; k++) if (students[i][k] === mentors[j][k]) s++;
            score[i].push(s);
        }
    }
    const full = 1 << m;
    const dp = new Array(full).fill(-1);
    dp[0] = 0;
    for (let mask = 0; mask < full; mask++) {
        if (dp[mask] < 0) continue;
        let i = 0, t = mask;
        while (t) { i += t & 1; t >>= 1; }
        if (i >= m) continue;
        for (let j = 0; j < m; j++) {
            if (!((mask >> j) & 1)) {
                const nm = mask | (1 << j);
                const val = dp[mask] + score[i][j];
                if (val > dp[nm]) dp[nm] = val;
            }
        }
    }
    return dp[full - 1];
};
